'use client';

import { AddCustomerDialog, EditCustomerDialog } from "@/components/customers/CustomerForm";
import {
    AlertDialog,
    AlertDialogAction,
    AlertDialogCancel,
    AlertDialogContent,
    AlertDialogDescription,
    AlertDialogFooter,
    AlertDialogHeader,
    AlertDialogTitle,
} from "@/components/ui/alert-dialog";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Skeleton } from "@/components/ui/skeleton";
import { Switch } from "@/components/ui/switch";
import {
    Table,
    TableBody,
    TableCell,
    TableHead,
    TableHeader,
    TableRow,
} from "@/components/ui/table";
import { useOnlineStatus } from "@/hooks/use-offline-data";
import { deleteCustomer } from "@/lib/actions/customer.actions";
import { getAllActiveCustomers } from "@/offline/offline-service";
import { CloudOff, Eye, RefreshCw, Search, Trash2 } from "lucide-react";
import { useTranslations } from "next-intl";
import { useRouter } from "next/navigation";
import { useCallback, useEffect, useRef, useState, useTransition } from "react";
import { toast } from "sonner";
import { useDebounce } from "use-debounce";

const PAGE_SIZE = 20;

interface Customer {
    id: string;
    name: string;
    phone: string;
    cnic: string | null;
    address: string | null;
    outstandingAmount: number;
    paidAmount: number;
    isActive: boolean;
}

interface CustomerApiRow {
    id: string;
    name: string;
    phone: string;
    cnic: string | null;
    address: string | null;
    outstandingAmount: string | number | null;
    paidAmount: string | number | null;
    isActive: boolean;
}

interface CustomersPage {
    data: Customer[];
    nextCursor: string | null;
    total: number;
}

interface CustomersApiResponse {
    data: CustomerApiRow[];
    nextCursor: string | null;
    total: number;
}

interface FetchCustomersOptions {
    search: string;
    outstandingOnly: boolean;
    cursor: string | null;
    forceOffline?: boolean;
}

function parseCurrencyValue(value: string | number | null | undefined): number {
    const parsed = typeof value === "number" ? value : Number.parseFloat(value ?? "0");
    return Number.isFinite(parsed) ? parsed : 0;
}

function mapCustomer(customer: CustomerApiRow): Customer {
    return {
        id: customer.id,
        name: customer.name,
        phone: customer.phone,
        cnic: customer.cnic,
        address: customer.address || null,
        outstandingAmount: parseCurrencyValue(customer.outstandingAmount),
        paidAmount: parseCurrencyValue(customer.paidAmount),
        isActive: customer.isActive,
    };
}

async function fetchCustomersFromServer({
    search,
    outstandingOnly,
    cursor,
}: FetchCustomersOptions): Promise<CustomersPage> {
    const params = new URLSearchParams();
    const trimmedSearch = search.trim();

    if (trimmedSearch) params.set("q", trimmedSearch);
    if (cursor) params.set("cursor", cursor);
    if (outstandingOnly) params.set("outstanding", "true");

    const queryString = params.toString();
    const res = await fetch(queryString ? `/api/customers?${queryString}` : "/api/customers", {
        cache: "no-store",
    });

    if (!res.ok) throw new Error("Failed to fetch customers");

    const json = await res.json() as CustomersApiResponse;
    return {
        data: json.data.map(mapCustomer),
        nextCursor: json.nextCursor,
        total: json.total,
    };
}

async function fetchCustomersOffline({
    search,
    outstandingOnly,
    cursor,
}: FetchCustomersOptions): Promise<CustomersPage> {
    const normalizedSearch = search.trim().toLowerCase();
    const offset = cursor ? Number.parseInt(cursor, 10) : 0;
    const safeOffset = Number.isFinite(offset) ? offset : 0;
    const customers = await getAllActiveCustomers();

    const filteredCustomers = customers
        .map((customer) => ({
            id: customer.id,
            name: customer.name,
            phone: customer.phone,
            cnic: customer.cnic,
            address: customer.address || null,
            outstandingAmount: customer.outstandingAmount,
            paidAmount: customer.paidAmount,
            isActive: customer.isActive,
        }))
        .filter((customer) => {
            const matchesSearch = !normalizedSearch
                || customer.name.toLowerCase().includes(normalizedSearch)
                || customer.phone.toLowerCase().includes(normalizedSearch)
                || (customer.cnic ?? "").toLowerCase().includes(normalizedSearch);

            return matchesSearch && (!outstandingOnly || customer.outstandingAmount > 0);
        })
        .sort((a, b) => {
            const nameSort = a.name.localeCompare(b.name, undefined, { sensitivity: "base" });
            return nameSort || a.id.localeCompare(b.id);
        });

    const data = filteredCustomers.slice(safeOffset, safeOffset + PAGE_SIZE);
    const nextOffset = safeOffset + data.length;

    return {
        data,
        nextCursor: nextOffset < filteredCustomers.length ? String(nextOffset) : null,
        total: filteredCustomers.length,
    };
}

function CustomersSkeletonRow() {
    return (
        <TableRow>
            <TableCell><Skeleton className="h-4 w-32" /></TableCell>
            <TableCell><Skeleton className="h-4 w-24" /></TableCell>
            <TableCell><Skeleton className="h-4 w-28" /></TableCell>
            <TableCell className="text-right"><Skeleton className="h-4 w-20 ml-auto" /></TableCell>
            <TableCell className="text-right"><Skeleton className="h-4 w-20 ml-auto" /></TableCell>
            <TableCell className="text-right">
                <div className="flex justify-end gap-1">
                    <Skeleton className="h-8 w-8 rounded-md" />
                    <Skeleton className="h-8 w-8 rounded-md" />
                    <Skeleton className="h-8 w-8 rounded-md" />
                </div>
            </TableCell>
        </TableRow>
    );
}

export function CustomersClient() {
    const router = useRouter();
    const isOnline = useOnlineStatus();
    const t = useTranslations("customers");
    const tc = useTranslations("common");
    const [isPending, startTransition] = useTransition();

    const [deleteTarget, setDeleteTarget] = useState<Customer | null>(null);
    const [searchQuery, setSearchQuery] = useState("");
    const [outstandingOnly, setOutstandingOnly] = useState(false);
    const [debouncedSearch] = useDebounce(searchQuery, 350);

    const [customers, setCustomers] = useState<Customer[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const [isLoadingMore, setIsLoadingMore] = useState(false);
    const [isOffline, setIsOffline] = useState(false);
    const [nextCursor, setNextCursor] = useState<string | null>(null);
    const [totalCustomers, setTotalCustomers] = useState(0);

    const sentinelRef = useRef<HTMLDivElement>(null);
    const activeRequestId = useRef(0);
    const isLoadingRef = useRef(false);
    const isLoadingMoreRef = useRef(false);

    const fetchCustomersPage = useCallback(async (
        options: FetchCustomersOptions,
        allowOfflineFallback: boolean
    ): Promise<CustomersPage> => {
        if (options.forceOffline || !isOnline) {
            setIsOffline(true);
            return fetchCustomersOffline(options);
        }

        try {
            const page = await fetchCustomersFromServer(options);
            setIsOffline(false);
            return page;
        } catch (error) {
            if (!allowOfflineFallback) throw error;
            console.warn("Server fetch failed, falling back to offline customers:", error);
            setIsOffline(true);
            return fetchCustomersOffline({ ...options, cursor: null });
        }
    }, [isOnline]);

    const loadFirstPage = useCallback(async (
        search: string,
        onlyOutstanding: boolean,
        silent = false
