        const requestId = activeRequestId.current + 1;
        activeRequestId.current = requestId;
        isLoadingRef.current = true;
        isLoadingMoreRef.current = false;
        setNextCursor(null);
        setIsLoadingMore(false);

        if (!silent) setIsLoading(true);

        try {
            const page = await fetchCustomersPage({
                search,
                outstandingOnly: onlyOutstanding,
                cursor: null,
            }, true);

            if (requestId !== activeRequestId.current) return;

            setCustomers(page.data);
            setNextCursor(page.nextCursor);
            setTotalCustomers(page.total);
        } catch (error) {
            if (requestId !== activeRequestId.current) return;
            console.error("Failed to load customers:", error);
            setCustomers([]);
            setNextCursor(null);
            setTotalCustomers(0);
        } finally {
            if (requestId === activeRequestId.current) {
                isLoadingRef.current = false;
                setIsLoading(false);
            }
        }
    }, [fetchCustomersPage]);

    useEffect(() => {
        loadFirstPage(debouncedSearch, outstandingOnly);
    }, [debouncedSearch, outstandingOnly, loadFirstPage]);

    const loadMore = useCallback(async () => {
        if (isLoadingRef.current || isLoadingMoreRef.current || !nextCursor) return;

        const requestId = activeRequestId.current;
        isLoadingMoreRef.current = true;
        setIsLoadingMore(true);

        try {
            const page = await fetchCustomersPage({
                search: debouncedSearch,
                outstandingOnly,
                cursor: nextCursor,
                forceOffline: isOffline,
            }, false);

            if (requestId !== activeRequestId.current) return;

            setCustomers((prevCustomers) => {
                const existingIds = new Set(prevCustomers.map((customer) => customer.id));
                const newCustomers = page.data.filter((customer) => !existingIds.has(customer.id));
                return [...prevCustomers, ...newCustomers];
            });
            setNextCursor(page.nextCursor);
            setTotalCustomers(page.total);
        } catch (error) {
            console.error("Failed to load more customers:", error);
            setNextCursor(null);
        } finally {
            isLoadingMoreRef.current = false;
            setIsLoadingMore(false);
        }
    }, [debouncedSearch, fetchCustomersPage, isOffline, nextCursor, outstandingOnly]);

    useEffect(() => {
        const sentinel = sentinelRef.current;
        if (!sentinel) return;

        const observer = new IntersectionObserver(
            (entries) => {
                if (entries[0]?.isIntersecting) {
                    loadMore();
                }
            },
            { rootMargin: "160px", threshold: 0.1 }
        );

        observer.observe(sentinel);
        return () => observer.disconnect();
    }, [loadMore]);

    const refetch = () => loadFirstPage(debouncedSearch, outstandingOnly);

    const handleDeactivate = () => {
        if (!deleteTarget) return;
        startTransition(async () => {
