import { db } from "@/db";
import { customers } from "@/db/schema";
import { type SQL, and, asc, eq, ilike, or, sql } from "drizzle-orm";
import { NextRequest, NextResponse } from "next/server";

const PAGE_SIZE = 20;

interface CustomerCursor {
    name: string;
    id: string;
}

function combineFilters(filters: SQL[]): SQL {
    return filters.length === 1 ? filters[0] : and(...filters)!;
}

function encodeCursor(customer: { name: string; id: string }): string {
    return Buffer.from(JSON.stringify({ name: customer.name, id: customer.id })).toString("base64url");
}

function decodeCursor(cursor: string): CustomerCursor | null {
    try {
        const parsed = JSON.parse(Buffer.from(cursor, "base64url").toString("utf8")) as Partial<CustomerCursor>;
        if (typeof parsed.name !== "string" || typeof parsed.id !== "string") {
            return null;
        }
        return { name: parsed.name, id: parsed.id };
    } catch {
        return null;
    }
}

export async function GET(req: NextRequest) {
    const { searchParams } = new URL(req.url);
    const query = searchParams.get("q")?.trim() ?? "";
    const cursorParam = searchParams.get("cursor");
    const outstandingOnly = searchParams.get("outstanding") === "true";

    try {
        const filters: SQL[] = [eq(customers.isActive, true)];

        if (query) {
            const searchPattern = `%${query}%`;
            const searchFilter = or(
                ilike(customers.name, searchPattern),
                ilike(customers.phone, searchPattern),
                ilike(customers.cnic, searchPattern)
            );

            if (searchFilter) {
                filters.push(searchFilter);
            }
        }

        if (outstandingOnly) {
            filters.push(sql`${customers.outstandingAmount}::numeric > 0`);
        }

        const baseWhereClause = combineFilters(filters);
        const cursor = cursorParam ? decodeCursor(cursorParam) : null;

        if (cursorParam && !cursor) {
            return NextResponse.json({ error: "Invalid customer cursor" }, { status: 400 });
        }

        const pageFilters = [...filters];
        if (cursor) {
            pageFilters.push(sql`(
                ${customers.name} > ${cursor.name}
                OR (${customers.name} = ${cursor.name} AND ${customers.id} > ${cursor.id})
            )`);
        }

        const pageWhereClause = combineFilters(pageFilters);
        const [rows, totalResult] = await Promise.all([
            db
                .select()
                .from(customers)
                .where(pageWhereClause)
                .orderBy(asc(customers.name), asc(customers.id))
                .limit(PAGE_SIZE + 1),
            db
                .select({ count: sql<number>`count(*)`.mapWith(Number) })
                .from(customers)
                .where(baseWhereClause),
        ]);

        const data = rows.slice(0, PAGE_SIZE);
        const nextCursor = rows.length > PAGE_SIZE && data.length > 0
            ? encodeCursor(data[data.length - 1])
            : null;

        return NextResponse.json({
            data,
            nextCursor,
            total: totalResult[0]?.count ?? 0,
        });
    } catch (error) {
        console.error("Customers API Error:", error);
        return NextResponse.json({ error: "Failed to fetch customers" }, { status: 500 });
    }
}

