   437	                                                        </Button>
   438	                                                        {!isOffline && (
   439	                                                            <>
   440	                                                                <EditCustomerDialog customer={customer} />
   441	                                                                <Button
   442	                                                                    variant="ghost"
   443	                                                                    size="icon"
   444	                                                                    className="text-destructive hover:text-destructive"
   445	                                                                    title={t("deactivateCustomer")}
   446	                                                                    onClick={() => setDeleteTarget(customer)}
   447	                                                                >
   448	                                                                    <Trash2 className="h-4 w-4" />
   449	                                                                </Button>
   450	                                                            </>
   451	                                                        )}
   452	                                                    </div>
   453	                                                </TableCell>
   454	                                            </TableRow>
   455	                                        ))}
   456	                                        {isLoadingMore && [...Array(4)].map((_, i) => (
   457	                                            <CustomersSkeletonRow key={`more-${i}`} />
   458	                                        ))}
   459	                                    </>
   460	                                )}
   461	                            </TableBody>
   462	                        </Table>
   463	                        <div ref={sentinelRef} className="h-4" />
   464	                        {!nextCursor && !isLoading && customers.length > 0 && (
   465	                            <p className="text-center text-xs text-muted-foreground pb-2">
   466	                                {tc("showing")} {customers.length} {tc("of")} {totalCustomers} {tc("entries")}
   467	                            </p>
   468	                        )}
   469	                    </CardContent>
   470	                </Card>
   471	            </div>
   472	
   473	            <AlertDialog
   474	                open={!!deleteTarget}
   475	                onOpenChange={(val) => {
   476	                    if (!val) setDeleteTarget(null);
   477	                }}
   478	            >
   479	                <AlertDialogContent>
   480	                    <AlertDialogHeader>
   481	                        <AlertDialogTitle>{t("deactivateCustomer")}</AlertDialogTitle>
   482	                        <AlertDialogDescription>
   483	                            {t("confirmDeactivateCustomer", { name: deleteTarget?.name || "" })}
   484	                        </AlertDialogDescription>
   485	                    </AlertDialogHeader>
   486	                    <AlertDialogFooter>
   487	                        <AlertDialogCancel>{tc("cancel")}</AlertDialogCancel>
   488	                        <AlertDialogAction
   489	                            onClick={handleDeactivate}
   490	                            disabled={isPending}
   491	                            className="bg-destructive text-destructive-foreground hover:bg-destructive/90"
   492	                        >
   493	                            {isPending ? tc("loading") : tc("confirm")}
   494	                        </AlertDialogAction>
   495	                    </AlertDialogFooter>
   496	                </AlertDialogContent>
   497	            </AlertDialog>
   498	        </>
   499	    );
   500	}
